INSERT INTO skills (name, author_id, version, tags, description, text, card)
VALUES (
    'changelog-writer',
    (SELECT id FROM authors WHERE name = 'rnditb2c'),
    '1.0.0',
    ARRAY['git', 'docs', 'productivity'],
    'Генерирует CHANGELOG.md на основе истории git-коммитов по формату Keep a Changelog',
    E'Проанализируй историю коммитов репозитория и сформируй CHANGELOG.md.\n\nФормат: Keep a Changelog (https://keepachangelog.com)\nДиапазон версий: {version_range}\nЯзык: {language}\n\nПравила:\n- Группируй изменения по категориям: Added, Changed, Fixed, Removed, Security\n- Определяй категорию по префиксу коммита (feat → Added, fix → Fixed, refactor → Changed)\n- Используй семантическое версионирование для заголовков версий\n- Для каждой версии указывай дату из соответствующего git-тега\n- Пиши описания изменений кратко и понятно для пользователя, не для разработчика\n\nЕсли CHANGELOG.md уже существует — дополни его, не перезаписывай.',
    E'# Changelog Writer\n\nСкилл анализирует историю git-коммитов и автоматически формирует структурированный CHANGELOG.md в формате Keep a Changelog.\n\n## Когда использовать\n\n- Подготовка релизных заметок перед публикацией новой версии\n- Восстановление истории изменений для проекта без changelog\n- Автоматизация документирования в CI/CD-пайплайне\n- Генерация changelog перед отправкой PR в открытый проект\n\n## Что делает скилл\n\n1. **Читает историю коммитов** — анализирует git log за указанный диапазон версий\n2. **Классифицирует изменения** — группирует по категориям: Added, Changed, Fixed, Removed, Security\n3. **Формирует структуру** — создаёт changelog строго по формату Keep a Changelog\n4. **Проставляет даты** — берёт дату релиза из git-тега\n\n## Как использовать\n\n### Базовое использование\n\n```\nСоздай CHANGELOG.md для этого репозитория\n```\n\n```\nСгенерируй changelog за последние три версии\n```\n\n### Диапазон версий\n\n```\nСоздай changelog от v1.0.0 до v2.0.0\n```\n\n```\nДобавь в changelog изменения с последнего релиза\n```\n\n## Пример\n\n**Пользователь**: «Создай CHANGELOG.md для этого репозитория»\n\n**Результат**:\n```\nАнализирую историю коммитов...\nНайдено: 47 коммитов, 3 версии\n\n## [2.1.0] - 2024-03-15\n### Added\n- Поддержка тёмной темы интерфейса\n- Экспорт данных в CSV\n\n### Fixed\n- Ошибка авторизации при истечении срока токена\n\nCHANGELOG.md сохранён ✓\n```\n\n## Советы\n\n- Используй Conventional Commits — скилл точнее классифицирует изменения\n- Указывай диапазон версий, чтобы не перегенерировать весь changelog\n- Скилл дополняет существующий changelog, а не заменяет его\n- Укажи язык, если changelog нужен не на английском\n\n## Частые сценарии\n\n- **Релиз**: формируй changelog прямо перед публикацией версии\n- **Open Source**: ведёт прозрачную историю изменений для пользователей\n- **Онбординг**: помогает новым участникам команды понять эволюцию проекта\n- **CI/CD**: автоматизирует документирование в пайплайне сборки'
)
ON CONFLICT (name, author_id) DO NOTHING;

INSERT INTO skills (name, author_id, version, tags, description, text, card)
VALUES (
    'code-documenter',
    (SELECT id FROM authors WHERE name = 'rnditb2c'),
    '1.0.0',
    ARRAY['coding', 'docs', 'productivity'],
    'Добавляет docstring, комментарии и обновляет README для указанных файлов или директорий',
    E'Проанализируй код в {path} и добавь документацию.\n\nЧто нужно сделать:\n- Напиши docstring к каждой функции, методу и классу без документации\n- Стиль: {doc_style} (Google / NumPy / Sphinx для Python; JSDoc для JS/TS; GoDoc для Go)\n- Добавь встроенные комментарии к нетривиальным блокам логики\n- Если указан флаг readme=true — обнови или создай раздел API в README.md\n\nОграничения:\n- Не изменяй логику кода — только добавляй документацию\n- Не удаляй существующие комментарии\n- Сохраняй оригинальный стиль форматирования файла',
    E'# Code Documenter\n\nСкилл анализирует ваш код и добавляет к нему профессиональную документацию: docstring к функциям и классам, комментарии к сложным блокам, а при необходимости — обновляет README.\n\n## Когда использовать\n\n- Подготовка кода к code review или публикации\n- Документирование унаследованного кода без документации\n- Генерация README-раздела для нового модуля или библиотеки\n- Стандартизация стиля документации в проекте\n\n## Что делает скилл\n\n1. **Анализирует структуру** — находит функции, классы и методы без docstring\n2. **Генерирует docstring** — описывает назначение, параметры, возвращаемые значения и исключения\n3. **Добавляет комментарии** — объясняет нетривиальную логику внутри функций\n4. **Обновляет README** — дополняет API-раздел при наличии флага\n\n## Как использовать\n\n### Базовое использование\n\n```\nЗадокументируй код в файле utils.py\n```\n\n```\nДобавь docstring ко всем функциям в директории src/\n```\n\n### С настройками\n\n```\nЗадокументируй api.go в стиле GoDoc и обнови README\n```\n\n```\nДобавь JSDoc-комментарии к файлу helpers.ts\n```\n\n## Пример\n\n**Пользователь**: «Задокументируй файл parser.py»\n\n**Результат**:\n```\nАнализирую parser.py...\nНайдено: 3 функции, 1 класс без документации\n\nДобавлено:\n✓ Docstring для класса TokenParser\n✓ Docstring для parse_tokens() с описанием параметров\n✓ Docstring для validate_syntax() с описанием исключений\n✓ Комментарии к регулярным выражениям\n\nФайл обновлён: parser.py\n```\n\n## Советы\n\n- Указывай стиль документации явно (Google, NumPy, Sphinx для Python)\n- Для Go стиль GoDoc применяется автоматически\n- Можно документировать как отдельный файл, так и целую директорию\n- Скилл не изменяет логику — безопасно применять к рабочему коду\n\n## Частые сценарии\n\n- **Code Review**: документируй код перед отправкой PR\n- **Онбординг**: помогает новым разработчикам быстро разобраться в проекте\n- **Open Source**: готовит код к публикации с понятной документацией\n- **Рефакторинг**: документируй после изменений, чтобы не потерять контекст'
)
ON CONFLICT (name, author_id) DO NOTHING;

INSERT INTO skills (name, author_id, version, tags, description, text, card)
VALUES (
    'dependency-auditor',
    (SELECT id FROM authors WHERE name = 'rnditb2c'),
    '1.0.0',
    ARRAY['coding', 'security', 'productivity'],
    'Проверяет зависимости проекта на устаревшие версии и известные уязвимости',
    E'Проверь зависимости проекта в {path} на наличие проблем.\n\nЧто нужно проверить:\n1. Устаревшие пакеты — найди зависимости, для которых доступны новые версии\n2. Уязвимости — проверь CVE-базу для каждой зависимости\n3. Неиспользуемые пакеты — найди зависимости, которые нигде не импортируются\n4. Конфликты версий — выяви несовместимые требования между пакетами\n\nДля каждой проблемы укажи:\n- Название пакета и текущую версию\n- Описание проблемы и уровень критичности (low / medium / high / critical)\n- Рекомендуемое действие (обновить до версии X / удалить / заменить на Y)\n\nВыведи итоговую сводку: количество проблем по уровню критичности.',
    E'# Dependency Auditor\n\nСкилл проверяет зависимости проекта на устаревшие версии, известные уязвимости, неиспользуемые пакеты и конфликты версий.\n\n## Когда использовать\n\n- Плановый аудит безопасности проекта\n- Подготовка к релизу или передаче проекта\n- После получения уведомления об уязвимости в зависимости\n- Уборка технического долга — удаление лишних пакетов\n\n## Что делает скилл\n\n1. **Проверяет актуальность** — сравнивает текущие версии с последними доступными\n2. **Сканирует уязвимости** — проверяет CVE-базы для каждой зависимости\n3. **Ищет неиспользуемые пакеты** — анализирует импорты в коде\n4. **Выявляет конфликты** — находит несовместимые требования между пакетами\n5. **Формирует отчёт** — группирует проблемы по критичности с рекомендациями\n\n## Как использовать\n\n### Базовое использование\n\n```\nПроверь зависимости этого проекта\n```\n\n```\nСделай аудит безопасности package.json\n```\n\n### Конкретные проверки\n\n```\nНайди устаревшие пакеты в requirements.txt\n```\n\n```\nПроверь, есть ли уязвимости в зависимостях Go-модуля\n```\n\n## Пример\n\n**Пользователь**: «Проверь зависимости этого проекта»\n\n**Результат**:\n```\nАудит зависимостей: package.json\nВсего пакетов: 34\n\nУязвимости:\n✗ lodash 4.17.20 — CVE-2021-23337 [high]\n  → Обновить до 4.17.21\n\nУстаревшие пакеты (5):\n⚠ react 17.0.2 → доступна 18.3.1\n⚠ axios 0.27.0 → доступна 1.7.2\n\nНеиспользуемые пакеты (2):\n− moment (не импортируется)\n− uuid (не импортируется)\n\nИтого: 1 критичная, 0 высоких, 5 предупреждений\n```\n\n## Советы\n\n- Запускай аудит регулярно — хотя бы раз в месяц\n- Начинай с исправления уязвимостей высокого и критического уровня\n- Удаляй неиспользуемые пакеты — они увеличивают поверхность атаки\n- Фиксируй версии зависимостей в lock-файле после обновления\n\n## Частые сценарии\n\n- **CI/CD**: добавь аудит в пайплайн перед деплоем\n- **Security Review**: обязательная проверка перед передачей проекта\n- **Рефакторинг**: убирай лишние зависимости вместе с неиспользуемым кодом\n- **Онбординг**: проверяй новые проекты сразу после клонирования'
)
ON CONFLICT (name, author_id) DO NOTHING;

INSERT INTO skills (name, author_id, version, tags, description, text, card)
VALUES (
    'log-analyzer',
    (SELECT id FROM authors WHERE name = 'rnditb2c'),
    '1.0.0',
    ARRAY['debugging', 'productivity', 'coding'],
    'Анализирует логи приложения: находит ошибки, паттерны и аномалии',
    E'Проанализируй логи из {log_source} и найди проблемы.\n\nЧто нужно сделать:\n1. Найди все ошибки и исключения — сгруппируй по типу и частоте\n2. Выяви паттерны — повторяющиеся последовательности событий до ошибки\n3. Обнаружь аномалии — всплески частоты событий, необычные задержки, неожиданные коды ответов\n4. Определи временные рамки — когда начались проблемы и как развивались\n\nПериод анализа: {time_range}\nФормат логов: {log_format}\n\nДля каждой найденной проблемы укажи:\n- Описание и первое вхождение\n- Количество повторений и динамику\n- Вероятную причину\n- Рекомендацию по устранению',
    E'# Log Analyzer\n\nСкилл анализирует логи приложения и выявляет ошибки, паттерны событий и аномалии — чтобы вы могли быстро найти причину проблемы.\n\n## Когда использовать\n\n- Расследование инцидента или сбоя в продакшене\n- Поиск первопричины периодических ошибок\n- Мониторинг поведения приложения после деплоя\n- Анализ производительности по временным меткам\n\n## Что делает скилл\n\n1. **Находит ошибки** — собирает все исключения и ошибки, группирует по типу\n2. **Выявляет паттерны** — ищет повторяющиеся последовательности событий до сбоя\n3. **Обнаруживает аномалии** — всплески частоты, задержки, неожиданные коды ответов\n4. **Строит временную шкалу** — показывает, когда началась проблема и как развивалась\n5. **Предлагает решения** — даёт рекомендации по каждой найденной проблеме\n\n## Как использовать\n\n### Базовое использование\n\n```\nПроанализируй логи в файле app.log\n```\n\n```\nНайди ошибки в логах за последний час\n```\n\n### Конкретные задачи\n\n```\nПочему приложение упало в 03:47? Посмотри в production.log\n```\n\n```\nНайди все таймауты в nginx.log за вчера\n```\n\n## Пример\n\n**Пользователь**: «Проанализируй логи в app.log за последние 24 часа»\n\n**Результат**:\n```\nПроанализировано: 142 847 строк, период: 2024-03-14 00:00 – 23:59\n\nОшибки (3 типа):\n✗ ConnectionTimeoutError — 847 раз (пик: 14:23–14:31)\n✗ NullPointerException в UserService:142 — 12 раз\n✗ HTTP 503 от payments-api — 34 раза\n\nАномалия обнаружена:\n⚠ В 14:20 резкий рост запросов к БД (×8 от нормы)\n  Вероятная причина: отсутствие индекса после миграции 14:18\n\nРекомендация: добавить индекс на users.created_at\n```\n\n## Советы\n\n- Указывай временной диапазон, чтобы сузить область анализа\n- Называй формат логов (JSON, logfmt, Apache) для точного парсинга\n- Для больших файлов указывай конкретное событие для поиска\n- Сравнивай логи до и после деплоя, чтобы найти регрессию\n\n## Частые сценарии\n\n- **Инцидент**: быстро найди первопричину сбоя в продакшене\n- **После деплоя**: убедись, что новая версия не принесла ошибок\n- **Производительность**: найди медленные запросы и узкие места\n- **Безопасность**: обнаружь подозрительную активность в access-логах'
)
ON CONFLICT (name, author_id) DO NOTHING;

INSERT INTO skills (name, author_id, version, tags, description, text, card)
VALUES (
    'test-generator',
    (SELECT id FROM authors WHERE name = 'rnditb2c'),
    '1.0.0',
    ARRAY['coding', 'testing', 'productivity'],
    'Генерирует юнит-тесты для указанного кода с покрытием граничных случаев',
    E'Напиши юнит-тесты для кода в {file_path}.\n\nФреймворк: {test_framework}\nМинимальное покрытие: {coverage_target}%\n\nДля каждой функции и метода напиши тесты:\n1. Позитивный сценарий — корректные входные данные, ожидаемый результат\n2. Граничные случаи — пустые значения, нули, максимальные значения, пустые коллекции\n3. Негативные сценарии — некорректные типы, ошибочные состояния, недоступные зависимости\n\nПравила:\n- Каждый тест проверяет ровно одно поведение\n- Названия тестов описывают сценарий: test_<функция>_<условие>_<ожидаемый результат>\n- Используй моки для внешних зависимостей (БД, HTTP, файловая система)\n- Не дублируй логику тестируемого кода в тестах',
    E'# Test Generator\n\nСкилл анализирует ваш код и генерирует юнит-тесты с покрытием позитивных сценариев, граничных случаев и обработки ошибок.\n\n## Когда использовать\n\n- Написание тестов для нового кода перед code review\n- Добавление тестов к унаследованному коду без покрытия\n- Проверка граничных случаев, о которых легко забыть\n- Ускорение TDD-цикла на этапе написания тестов\n\n## Что делает скилл\n\n1. **Анализирует сигнатуры** — изучает параметры, типы и возвращаемые значения функций\n2. **Определяет сценарии** — позитивный путь, граничные случаи, обработка ошибок\n3. **Генерирует тесты** — пишет тест-кейсы с понятными названиями и комментариями\n4. **Создаёт моки** — изолирует внешние зависимости (БД, HTTP, файловая система)\n5. **Проверяет покрытие** — оценивает процент покрытия и предлагает дополнительные тесты\n\n## Как использовать\n\n### Базовое использование\n\n```\nНапиши тесты для файла auth.py\n```\n\n```\nСгенерируй юнит-тесты для всех функций в utils/\n```\n\n### С настройками\n\n```\nНапиши pytest-тесты для parser.py с покрытием 90%\n```\n\n```\nСгенерируй Jest-тесты для компонента UserForm.tsx\n```\n\n## Пример\n\n**Пользователь**: «Напиши тесты для функции calculate_discount() в pricing.py»\n\n**Результат**:\n```\nАнализирую calculate_discount()...\nПараметры: price (float), user_type (str), coupon (str | None)\nВозвращает: float\nГраничные случаи: price=0, неизвестный user_type, истёкший купон\n\nСгенерировано 8 тестов:\n✓ test_calculate_discount_regular_user_returns_no_discount\n✓ test_calculate_discount_premium_user_returns_20_percent\n✓ test_calculate_discount_with_valid_coupon_applies_extra\n✓ test_calculate_discount_with_expired_coupon_ignores_it\n✓ test_calculate_discount_zero_price_returns_zero\n✓ test_calculate_discount_unknown_user_type_raises_error\n✓ test_calculate_discount_negative_price_raises_error\n✓ test_calculate_discount_combined_discount_does_not_exceed_cap\n\nФайл сохранён: test_pricing.py\n```\n\n## Советы\n\n- Указывай тестовый фреймворк явно (pytest, unittest, Jest, Go testing)\n- Называй целевое покрытие — скилл добавит тесты для недостаточно покрытых путей\n- Проверяй сгенерированные моки — убедись, что они точно имитируют реальное поведение\n- Используй скилл итеративно: сначала сгенерируй, потом дополни вручную\n\n## Частые сценарии\n\n- **Code Review**: добавляй тесты перед отправкой PR\n- **TDD**: генерируй скелет тестов до написания реализации\n- **Регрессия**: покрывай тестами баги, чтобы они не вернулись\n- **Рефакторинг**: убедись, что поведение не изменилось после правок'
)
